22	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	const BLOCK_BASE = 60;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const DEDUCTIBLE = 100;
