100	type Policy = { items: Item[]; capRemaining: number };
101	
102	const insuranceSum = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
104	
105	const newPolicy = (items: Item[]): Policy => ({
106	  items,
107	  capRemaining: 2 * insuranceSum(items),
108	});
109	
110	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
111	  const totalPayout = incident.damages.reduce(
112	    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
113	    0,
114	  );
115	  policy.capRemaining -= totalPayout;
116	  return { payout: totalPayout, remainingCap: policy.capRemaining };
117	};
