123	      policies[stepIndex] = newPolicy(step.items);
124	      return { premium: quotePremium(step.items, scenario.customer, stepIndex) };
125	    }
126	    return processClaim(policies[step.policy], step.incident);
127	  });
128	  return { results };
129	};
